diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..b92dc1802fef 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4832,6 +4832,51 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
   if (Instruction *R = foldICmpOrXX(I, Q, *this))
     return R;

+  // (~X ^ Y) cmp ~X --> (X ^ Y) cmp' X
+  // (~X ^ Y) cmp ~Z --> (X ^ Y) cmp' Z
+  // This is based on the fact that ~ is bitwise NOT, and when comparing
+  // (~X ^ Y) with ~X, we can transform it to compare (X ^ Y) with X.
+  // The predicate is swapped because ~ is a bitwise complement.
+  {
+    Value *X, *Y, *Z;
+    // Match (xor (xor X, -1), Y) cmp (xor X, -1)
+    // i.e., (~X ^ Y) cmp ~X
+    if (match(Op0, m_c_Xor(m_Not(m_Value(X)), m_Value(Y))) &&
+        match(Op1, m_Not(m_Specific(X)))) {
+      // At least one use to prevent code bloat
+      if (Op0->hasOneUse() || Op1->hasOneUse()) {
+        Value *NewXor = Builder.CreateXor(X, Y);
+        return new ICmpInst(I.getSwappedPredicate(), NewXor, X);
+      }
+    }
+    // Match (xor (xor X, -1), Y) cmp (xor Z, -1)
+    // i.e., (~X ^ Y) cmp ~Z
+    if (match(Op0, m_c_Xor(m_Not(m_Value(X)), m_Value(Y))) &&
+        match(Op1, m_Not(m_Value(Z)))) {
+      // At least one use to prevent code bloat
+      if (Op0->hasOneUse() || Op1->hasOneUse()) {
+        Value *NewXor = Builder.CreateXor(X, Y);
+        return new ICmpInst(I.getSwappedPredicate(), NewXor, Z);
+      }
+    }
+    // Match commuted version: ~X cmp (~X ^ Y)
+    if (match(Op1, m_c_Xor(m_Not(m_Value(X)), m_Value(Y))) &&
+        match(Op0, m_Not(m_Specific(X)))) {
+      if (Op0->hasOneUse() || Op1->hasOneUse()) {
+        Value *NewXor = Builder.CreateXor(X, Y);
+        return new ICmpInst(I.getSwappedPredicate(), X, NewXor);
+      }
+    }
+    // Match commuted version: ~Z cmp (~X ^ Y)
+    if (match(Op1, m_c_Xor(m_Not(m_Value(X)), m_Value(Y))) &&
+        match(Op0, m_Not(m_Value(Z)))) {
+      if (Op0->hasOneUse() || Op1->hasOneUse()) {
+        Value *NewXor = Builder.CreateXor(X, Y);
+        return new ICmpInst(I.getSwappedPredicate(), Z, NewXor);
+      }
+    }
+  }
+
   {
     // Try to remove shared multiplier from comparison:
     // X * Z u{lt/le/gt/ge}/eq/ne Y * Z

log.source_program:
define i1 @test_sle_xor(i32 %x, i32 %y) {
  %xor1 = xor i32 %y, -1
  %xor2 = xor i32 %xor1, %x
  %r = icmp sle i32 %xor2, %xor1
  ret i1 %r
}

log.expect_optimized_program:
define i1 @test_sle_xor(i32 %x, i32 %y) {
  %1 = xor i32 %y, %x
  %r = icmp sge i32 %1, %y
  ret i1 %r
}

